import math

def poly_derivative(xs: list, x: float):

    return sum([i * coeff * math.pow(x, i - 1) for i, coeff in enumerate(xs) if i > 0])

def find_zero(xs: list):

    if len(xs) % 2 != 0:
        raise ValueError("The number of coefficients must be even.")

    guess = 0.0

    tolerance = 1e-7
    max_iterations = 1000

    for _ in range(max_iterations):
        f_value = poly(xs, guess)
        f_prime_value = poly_derivative(xs, guess)

        if abs(f_prime_value) < tolerance:
            raise ValueError("Derivative is too close to zero. No solution found.")

        new_guess = guess - f_value / f_prime_value

        if abs(new_guess - guess) < tolerance:
            return round(new_guess, 2)

        guess = new_guess

    raise ValueError("Maximum iterations reached. No solution found.")

