    if len(xs) % 2 != 0:
        raise ValueError("Polynomial must have an even number of coefficients")

    a, b = -1.0, 1.0
    while poly(xs, a) * poly(xs, b) > 0:
        a *= 2
        b *= 2

    tolerance = 1e-6
    max_iterations = 1000
    for _ in range(max_iterations):
        c = (a + b) / 2.0
        if abs(poly(xs, c)) < tolerance:
            return round(c, 2)

        if poly(xs, a) * poly(xs, c) < 0:
            b = c
        else:
            a = c

    raise ValueError("No zero found within tolerance")

