def dfs(x, y, k, current_path):
    if (x, y, k) in memo:
        return memo[(x, y, k)]

    if k == 0:
        return current_path

    min_path = float('inf')
    min_sequence = []

    for dx, dy in directions:
        nx, ny = x + dx, y + dy

        if 0 <= nx < N and 0 <= ny < N:
            next_value = grid[nx][ny]

            if len(current_path) == 1 or current_path[-2] != next_value:
                new_sequence = current_path + [next_value]

                result = dfs(nx, ny, k - 1, new_sequence)

                if result < min_path:
                    min_path = result
                    min_sequence = new_sequence

    memo[(x, y, k)] = (min_path, min_sequence)
    return (min_path, min_sequence)

